{
  "verses": [
    {
      "n": 21,
      "column": "left",
      "text": "Mans Behrne/ lai Schihs\nLeetas no tawahm Azzim ne at-\nkahvj/ paglabbo to pastahwigu\nBuhfchanu un apdohmign Prahtu.\n"
    },
    {
      "n": 22,
      "column": "left",
      "text": "Jo tee buhs tawas Dweh-\nfeles Dsihwiba/ un weens jauks\nglihtums tawam Kaklam.\n"
    },
    {
      "n": 23,
      "column": "left",
      "text": "Tad staigast tu drohfschi\ntawu Zeltu/ un tawa Kahja ne\ndausifees.\n"
    },
    {
      "n": 24,
      "column": "left",
      "text": "Apguldamees tu ne bih-\nfees/ bet gullesi/ un taws Meegs\nbuhs gards.\n"
    },
    {
      "n": 25,
      "column": "left",
      "text": "Tu ne bihfees no peepe-\nschas Jsbailes/ neds no Trohks-\nneſchanas to Besdeewign/ kad\nta nahk.\n"
    },
    {
      "n": 26,
      "column": "left",
      "text": "Jo tas KUNGS buhs\ntaws Patwerums/ un pafar-\ngahs tawu Kahju/ ka ta ne tohp\neewaldsinata.\n"
    },
    {
      "n": 27,
      "column": "left",
      "text": "Ne leedsees labbu darriht\ntam/ kam tas peenahk/ kad tew\nno Deewa pee Rohkas irr to\ndarrtht.\n"
    },
    {
      "n": 28,
      "column": "left",
      "text": "Ne faekki us tawn Tuwa-\nfu: Eij nohst/ un nahz atkat\nschur/ tad es rihtu dohfschu/ kad\ntew (gann) teju pee Rohkas irr.\n"
    },
    {
      "n": 29,
      "column": "left",
      "text": "Ne dohma kannu prett\ntawu Tuwaku/ kad tas pee te-\nwis dfihwo.\n"
    },
    {
      "n": 30,
      "column": "left",
      "text": "Ne barrees ar jebkahdu\nZilweku bes Wainas/ kad wiꞥſch\ntew ne irr tauna darrigs.\n"
    },
    {
      "n": 31,
      "column": "left",
      "text": "Ne skaudi tu weenu\nWaträs-Darritaju/ un ne pee-\n"
    },
    {
      "n": 32,
      "column": "right",
      "text": "Kas atkahpjahs/ tas\ntam KUNGA M weena Neg\ntiba/ bet winna Noslehpums\npee teem Taisneem.\n"
    },
    {
      "n": 33,
      "column": "right",
      "text": "Ta KUNGA Lahti\neeſſch ta Besdeevisa Nammi\nbet to Taisno Mahjas-We\nwinſch fahtinahs.\n"
    },
    {
      "n": 34,
      "column": "right",
      "text": "Teescham/ tobs Meh\ntajus wiꞥſch pats mehdiths/\nteem Pasemmineem parahdi\nwiꞥſch Schehlastibu.\n"
    },
    {
      "n": 35,
      "column": "right",
      "text": "Tee Gudree eemanto\nGohdu/ bet tee Gefki uskrauj\nfewim Raunu.\n"
    },
    {
      "n": 1,
      "column": "right",
      "text": "Lautajt mannt Behr\nta Tehwa Pamahzisch\nnu/ un usmannajt\nSapraichanu afiht.\n"
    },
    {
      "n": 2,
      "column": "right",
      "text": "Jo es dohmu jums labb\nMahzibu/ ne atfahjeet mann\nBanffibu.\n"
    },
    {
      "n": 3,
      "column": "right",
      "text": "Jo es biju manna Tehw\nDehls/ janfajs un weens ween\ngajs preekſch mannas Mahtes.\n"
    },
    {
      "n": 4,
      "column": "right",
      "text": "Un wiꞥſchmahzija mann\nun fazzija us man: Laid taw\nSirde mannas Wahrdus pee\naem/ turri mannas Baufsus\ntad tu dfihwoft.\n"
    },
    {
      "n": 5,
      "column": "right",
      "text": "Sarmanto Gudribu/ fa\nmanto Sapraichanu/ ne aismit\nsti\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
